namespace BgControls.Windows.Controls.DragDrop;/// <summary>/// 表示拖放操作过程中不同阶段状态的枚举./// </summary>public enum DragStatus{    /// <summary>    /// 无状态或初始状态.    /// </summary>    None,    /// <summary>    /// 正在查询是否允许启动拖拽.    /// </summary>    DragQuery,    /// <summary>    /// 拖拽操作正在进行中.    /// </summary>    DragInProgress,    /// <summary>    /// 拖拽阶段已成功完成.    /// </summary>    DragComplete,    /// <summary>    /// 拖拽操作已取消.    /// </summary>    DragCancel,    /// <summary>    /// 正在查询放置目标是否有效.    /// </summary>    DropDestinationQuery,    /// <summary>    /// 正在向放置源查询操作许可.    /// </summary>    DropSourceQuery,    /// <summary>    /// 当前位置允许执行放置操作.    /// </summary>    DropPossible,    /// <summary>    /// 当前位置不允许执行放置操作.    /// </summary>    DropImpossible,    /// <summary>    /// 放置操作已成功完成.    /// </summary>    DropComplete,    /// <summary>    /// 放置操作已取消.    /// </summary>    DropCancel,}